// Define a function to validate the table structure
function validateTable(tableStr) {
  const rows = tableStr.match(/<tr>.*?</tr>/g);
  const numCells = rows[0].match(/<td>.*?</td>/g).length;
  for (let i = 0; i < rows.length; i++) {
    if (rows[i].match(/<td>.*?</td>/g).length !== numCells) {
      return false;
    }
  }
  return true;
}

