class Solution:
    def validateTable(self, tableStr):
        rows = tableStr.split('<tr>')[1:-1]
        cells = tableStr.split('<td>')[1:-1]
        for row in rows:
            if len(cells) !== len(row.split('<td>')):
                return False
        return True
